import{_ as t,o as a,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Appier","description":"","frontmatter":{"title":"Appier","slug":"appier"},"headers":[],"relativePath":"marketer-hub/appier.md","filePath":"marketer-hub/appier.md"}'),o={name:"marketer-hub/appier.md"};function i(s,e,p,l,d,c){return a(),r("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>.png &quot;appier-logo.png&quot;)</p><p><a href="https://www.appier.com/en/" target="_blank" rel="noreferrer">Appier</a> is a technology company that makes it easy for businesses to use artificial intelligence to grow and succeed in a cross-screen era. The fact is, we are living in a post-mobile world, where cross-screen is no longer optional.</p><p><strong>PARTNER CAPABILITIES</strong></p><table tabindex="0"><thead><tr><th>Partner Capabilities</th><th>Details</th></tr></thead><tbody><tr><td>Company Type</td><td>Contact support at Appier for more information.</td></tr><tr><td>Deep Linking</td><td>Contact support at Appier for more information.</td></tr><tr><td>Attribution</td><td>Contact support at Appier for more information.</td></tr><tr><td>Ad Campaign Types</td><td>Contact support at Appier for more information.</td></tr><tr><td>Ad Formats</td><td>Contact support at Appier for more information.</td></tr><tr><td>Click Types</td><td>Contact support at Appier for more information.</td></tr><tr><td>Supported Platforms</td><td>- iOS - Android</td></tr><tr><td>Link Wrapping</td><td>Contact support at Appier for more information.</td></tr><tr><td>Cost Ingestion Support</td><td>Contact support at Appier for more information.</td></tr><tr><td>Cost Ingestion Types</td><td>Contact support at Appier for more information.</td></tr><tr><td>Pricing Models</td><td>- CPI - CPA</td></tr></tbody></table><h2 id="_1-complete-ads-prerequisites" tabindex="-1">1. Complete Ads Prerequisites <a class="header-anchor" href="#_1-complete-ads-prerequisites" aria-label="Permalink to &quot;1. Complete Ads Prerequisites&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">DEVELOPER MAY BE REQUIRED</p><p>The following Ads prerequisite includes providing URI schemes and other components that may require a developer:</p><ul><li><a href="https://branch.dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>Add Deep Link Routing &amp; Required Redirects</strong></a></li></ul></div><div class="warning custom-block"><p class="custom-block-title">DEVELOPER REQUIRED</p><p>The following Ads prerequisites involve app code changes:</p><ul><li><a href="./native-sdks-overview.html"><strong>Implement the Branch SDK</strong></a></li></ul></div><h2 id="_2-enable-the-integration" tabindex="-1">2. Enable the Integration <a class="header-anchor" href="#_2-enable-the-integration" aria-label="Permalink to &quot;2. Enable the Integration&quot;">​</a></h2><ol><li><p>Visit the <a href="https://dashboard.branch.io/ads" target="_blank" rel="noreferrer"><strong>Ads</strong></a> page on the Branch dashboard.</p></li><li><p>Select <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a> from the sidebar.</p></li><li><p>Search for Appier.</p></li><li><p>Select <strong>Appier</strong>, and click <strong>Save &amp; Enable</strong>.</p><p>.png &quot;appier-enable.png&quot;)</p></li></ol><h2 id="_3-enable-postbacks" tabindex="-1">3. Enable Postbacks <a class="header-anchor" href="#_3-enable-postbacks" aria-label="Permalink to &quot;3. Enable Postbacks&quot;">​</a></h2><p>When Branch measures a conversion (install or other event), it determines which ad network or partner is responsible for generating the action, then attributes credit to the proper partner accordingly. Branch notifies the Ad partner of these events via postbacks which are turned on when you enable any Ads integrated partner.</p><p>Basic postbacks will automatically be activated for events like Install and Purchase when you enable your ad partner.</p><p>Branch’s postback system is highly <a href="./basic-postback-configuration.html">customizable</a>; you can set up postbacks for specific events, as well as specific subsections of events, filtered by link data, user data or event properties.</p><p>You can then <a href="./branch-universal-ads-advanced.html#addingenabling-more-postbacks">add additional postbacks</a>, for example, if you wanted to add postbacks for custom events that are specific to your app like Account Created. You can also <a href="./branch-universal-ads-advanced.html#addingenabling-more-postbacks">edit postbacks</a> if there&#39;s additional data you really need to pass along to your ad partner.</p><p>.png &quot;appier-pb.png&quot;)</p><div class="danger custom-block"><p class="custom-block-title">Troubleshoot Postbacks</p><p>There may be times when you need to reset a partner&#39;s settings; i.e. when a partner updates their postback templates or when perhaps you&#39;ve made a mistake during partner setup. Resetting a partner&#39;s settings allows you to re-enable the partner integration with the correct information to accurately measure and attribute conversion.</p><p>Note, by resetting your partner settings, this will:</p><ul><li>Disable the ad partner</li><li>Clear out all of your saved credentials and postbacks that are already setup</li><li>Return the ad partner to its basic configuration</li></ul><p><a href="./reset-my-ad-partners-settings.html">Learn more here on how to reset your ad partner&#39;s settings.</a></p></div><h2 id="_4-verify-integration-setup" tabindex="-1">4. Verify Integration Setup <a class="header-anchor" href="#_4-verify-integration-setup" aria-label="Permalink to &quot;4. Verify Integration Setup&quot;">​</a></h2><details><summary>View Link Parameters</summary><p>By default, Branch automatically appends partner-specific link parameters during the link creation process. When a user clicks on the link, Appier provides the appropriate parameter values which Branch ingests and uses for attribution and reporting purposes.</p><p>Below are the link parameters that Branch automatically appends for this ad partner:</p><p>.png &quot;appier-link-config.png&quot;)</p></details><details><summary>View Attribution Windows</summary><p>Branch employs <a href="./attribution-windows-link-settings.html">Attribution Windows</a> at both the app level and the ad partner level. When you enable Appier, Branch uses the attribution windows you&#39;ve selected at the app level.</p><p>However, you can choose to use the attribution windows provided specifically by Appier. To do so, toggle the <strong>Use Ad Partner Attribution Windows</strong> to on. Please keep in mind that only conversions attributed to this ad partner will use these specific windows; otherwise, the app-level windows prevail.</p><p>.png &quot;Screen Shot 2020-12-14 at 3.25.52 PM.png&quot;)</p></details><details><summary>Test Postbacks</summary><p>Testing your configuration is a very important step that we highly recommend you take the time to complete before going live with marketing campaigns.</p><p>Learn how to <a href="./testing-postbacks.html">Test Postbacks</a></p><p>.png &quot;appier-pb-testing.png&quot;)</p></details><h2 id="_5-create-a-branch-link" tabindex="-1">5. Create a Branch Link <a class="header-anchor" href="#_5-create-a-branch-link" aria-label="Permalink to &quot;5. Create a Branch Link&quot;">​</a></h2><p>If you are running paid advertising campaigns, you&#39;ll want to create a Branch Ad Link so we can accurately attribute resulting app conversions to the appropriate advertising partner.</p><p>Branch Ad Links support deferred deep linking, Android App Links, and iOS Universal Links, as well as web and app conversions.</p><p>Learn how to <a href="./ad-links.html">Create A Branch Ad Link</a>.</p>',25)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
